import json

with open('chart.html') as f:
    html = f.read()

# Extract the JSON spec from the HTML
import re
m = re.search(r'var spec = ({.*?});\s*var opt', html, re.DOTALL)
if not m:
    m = re.search(r'spec\s*=\s*({.*?});', html, re.DOTALL)
if m:
    spec = json.loads(m.group(1))
else:
    # Try to find any JSON-like block
    m = re.search(r'\"\$schema\".*', html)
    print('Trying alternative extraction...')
    print(html[:500])
    exit(1)

# Check 1: vconcat with exactly two entries
print('=== Check 1: vconcat field ===')
if 'vconcat' in spec:
    print(f'vconcat entries: {len(spec[\"vconcat\"])}')
else:
    print('NO vconcat found! Top-level keys:', list(spec.keys()))

# Check 2: Both entries have area marks
print()
print('=== Check 2: Area marks in both panels ===')
for i, entry in enumerate(spec.get('vconcat', [])):
    def find_mark(obj, depth=0):
        if depth > 20:
            return None
        if isinstance(obj, dict):
            if 'mark' in obj:
                return obj['mark']
            for v in obj.values():
                res = find_mark(v, depth+1)
                if res:
                    return res
        elif isinstance(obj, list):
            for item in obj:
                res = find_mark(item, depth+1)
                if res:
                    return res
        return None
    mark = find_mark(entry)
    print(f'  Panel {i}: mark = {json.dumps(mark)[:100]}')

# Check 3: Lower panel has selection_interval restricted to x
print()
print('=== Check 3: selection_interval on lower panel ===')
lower = spec['vconcat'][1]
def find_params(obj, depth=0):
    params = []
    if depth > 20:
        return params
    if isinstance(obj, dict):
        if 'params' in obj:
            params.append(obj['params'])
        for v in obj.values():
            params.extend(find_params(v, depth+1))
    elif isinstance(obj, list):
        for item in obj:
            params.extend(find_params(item, depth+1))
    return params

lower_params = find_params(lower)
print(f'  Params found: {json.dumps(lower_params)[:500]}')

# Check 4: Upper panel x encoding scale domain references brush
print()
print('=== Check 4: x-scale domain references brush ===')
upper = spec['vconcat'][0]
def find_x_scale(obj, depth=0):
    if depth > 20:
        return None
    if isinstance(obj, dict):
        if 'encoding' in obj and isinstance(obj['encoding'], dict):
            x = obj['encoding'].get('x')
            if x and isinstance(x, dict):
                scale = x.get('scale')
                if scale:
                    return scale
        for v in obj.values():
            res = find_x_scale(v, depth+1)
            if res:
                return res
    elif isinstance(obj, list):
        for item in obj:
            res = find_x_scale(item, depth+1)
            if res:
                return res
    return None

x_scale = find_x_scale(upper)
print(f'  x scale: {json.dumps(x_scale)}')

# Check 5: Upper panel has rule mark with window/aggregate + filter
print()
print('=== Check 5: rule mark with transform ===')
def find_rule_with_transforms(obj, depth=0):
    if depth > 20:
        return None
    if isinstance(obj, dict):
        mark = obj.get('mark')
        if (mark == 'rule' or (isinstance(mark, dict) and mark.get('type') == 'rule')):
            transforms = []
            def collect_transforms(o, d=0):
                if d > 20:
                    return
                if isinstance(o, dict):
                    if 'transform' in o:
                        transforms.append(o['transform'])
                    for v in o.values():
                        collect_transforms(v, d+1)
                elif isinstance(o, list):
                    for item in o:
                        collect_transforms(item, d+1)
            collect_transforms(obj)
            return {'mark': mark, 'transforms': transforms}
        for v in obj.values():
            res = find_rule_with_transforms(v, depth+1)
            if res:
                return res
    elif isinstance(obj, list):
        for item in obj:
            res = find_rule_with_transforms(item, depth+1)
            if res:
                return res
    return None

rule_info = find_rule_with_transforms(upper)
print(f'  Rule info: {json.dumps(rule_info, indent=2)[:1000]}')
"

